1: const std = @import("std");
2: 
3: pub fn build(b: *std.Build) void {
4:     const optimize = b.standardOptimizeOption(.{});
5: 
6:     // Match LSMinimumSystemVersion in Info.plist
7:     const target = b.resolveTargetQuery(.{
8:         .os_version_min = .{ .semver = .{ .major = 26, .minor = 0, .patch = 0 } },
9:     });
10: 
11:     // Step 1: Build the Zig static library
12:     const lib = b.addLibrary(.{
13:         .name = "lex",
14:         .linkage = .static,
15:         .root_module = b.createModule(.{
16:             .root_source_file = b.path("src/liblex.zig"),
17:             .target = target,
18:             .optimize = optimize,
19:         }),
20:     });
21: 
22:     // Step 2: Re-pack the archive (Zig master workaround for non-8-byte-aligned members)
23:     const repack = b.addSystemCommand(&.{
24:         "/bin/sh", "-c",
25:         \\tmp=$(mktemp -d) && \
26:         \\cp "$1" "$tmp/lib.a" && \
27:         \\(cd "$tmp" && ar x lib.a && rm lib.a && chmod 644 *.o && /usr/bin/ar rcs lib.a *.o) && \
28:         \\cp "$tmp/lib.a" "$1" && \
29:         \\rm -rf "$tmp"
30:         ,
31:         "--",
32:     });
33:     repack.addArtifactArg(lib);
34:     repack.has_side_effects = true;
35: 
36:     // Derive Swift target triple from host arch + macOS deployment target
37:     const arch = target.result.cpu.arch;
38:     const swift_arch: []const u8 = switch (arch) {
39:         .aarch64 => "arm64",
40:         .x86_64 => "x86_64",
41:         else => @panic("unsupported host architecture for macOS build"),
42:     };
43:     const swift_target = b.fmt("{s}-apple-macosx26.0", .{swift_arch});
44: 
45:     // Step 3: Compile Swift and link with the Zig library
46:     const swiftc = b.addSystemCommand(&.{
47:         "swiftc",
48:         "macos/Lex.swift",
49:         "-import-objc-header",
50:         "src/liblex.h",
51:         "-target",
52:     });
53:     swiftc.addArg(swift_target);
54:     swiftc.addPrefixedDirectoryArg("-L", lib.getEmittedBinDirectory());
55:     swiftc.addArgs(&.{"-llex"});
56:     swiftc.addArgs(&.{ "-o", "macos/Lex.app/Contents/MacOS/Lex" });
57:     swiftc.step.dependOn(&repack.step);
58:     swiftc.has_side_effects = true;
59: 
60:     // Step 4: Ad-hoc codesign
61:     const codesign = b.addSystemCommand(&.{
62:         "codesign", "-f", "-s", "-", "macos/Lex.app",
63:     });
64:     codesign.step.dependOn(&swiftc.step);
65:     codesign.has_side_effects = true;
66: 
67:     // Wire into default install step
68:     b.getInstallStep().dependOn(&codesign.step);
69: 
70:     // `zig build run` Б─■ open the app
71:     const run = b.addSystemCommand(&.{ "open", "macos/Lex.app" });
72:     run.step.dependOn(b.getInstallStep());
73:     const run_step = b.step("run", "Build and open Lex.app");
74:     run_step.dependOn(&run.step);
75: }

1: #ifndef LIBLEX_H
2: #define LIBLEX_H
3: 
4: #include <stdint.h>
5: #include <stdbool.h>
6: 
7: typedef struct {
8:     uint8_t num_backspaces;
9:     uint8_t num_chars;
10:     bool swallow_event;
11:     const uint16_t *chars;
12: } ProcessKeyEventResult;
13: 
14: ProcessKeyEventResult process_key_event(uint16_t char_code);
15: ProcessKeyEventResult process_backspace(void);
16: void reset_state(void);
17: 
18: #endif

1: const State = enum(u8) {
2:     idle,
3:     one_e,
4:     circumflex,
5:     literal,
6: };
7: 
8: const ProcessKeyEventResult = extern struct {
9:     num_backspaces: u8,
10:     num_chars: u8,
11:     swallow_event: bool,
12:     chars: [*]const u16,
13: };
14: 
15: // --- Internal variables ---
16: 
17: var state: State = .idle;
18: var first_e_upper: bool = false;
19: var gap: u8 = 0;
20: var bufs: [2][2]u16 = .{ .{ 0, 0 }, .{ 0, 0 } };
21: var active: u1 = 0;
22: 
23: const passthrough: ProcessKeyEventResult = .{
24:     .num_backspaces = 0,
25:     .num_chars = 0,
26:     .swallow_event = false,
27:     .chars = @ptrCast(&bufs[0]),
28: };
29: 
30: // --- Internal functions ---
31: 
32: fn emit(num_backspaces: u8, chars: []const u16) ProcessKeyEventResult {
33:     const buf = @as([*]u16, @ptrCast(&bufs[active]));
34:     for (chars, 0..) |c, i| buf[i] = c;
35:     active ^= 1;
36:     return .{
37:         .num_backspaces = num_backspaces,
38:         .num_chars = @intCast(chars.len),
39:         .swallow_event = true,
40:         .chars = buf,
41:     };
42: }
43: 
44: fn is_e(c: u16) bool {
45:     return c == 'e' or c == 'E';
46: }
47: 
48: fn is_alphanumeric(c: u16) bool {
49:     return (c >= '0' and c <= '9') or
50:         (c >= 'A' and c <= 'Z') or
51:         (c >= 'a' and c <= 'z');
52: }
53: 
54: fn handle_e(char_code: u16) ProcessKeyEventResult {
55:     const upper = char_code == 'E';
56:     switch (state) {
57:         .idle => {
58:             state = .one_e;
59:             first_e_upper = upper;
60:             return passthrough;
61:         },
62:         .one_e => {
63:             state = .circumflex;
64:             const c: u16 = if (first_e_upper) 0x00CA else 0x00EA;
65:             return emit(1, &.{c});
66:         },
67:         .circumflex => {
68:             state = .literal;
69:             const c0: u16 = if (first_e_upper) 'E' else 'e';
70:             const c1: u16 = if (upper) 'E' else 'e';
71:             return emit(1, &.{ c0, c1 });
72:         },
73:         .literal => unreachable,
74:     }
75: }
76: 
77: // --- Public functions ---
78: 
79: export fn reset_state() void {
80:     state = .idle;
81:     first_e_upper = false;
82:     gap = 0;
83: }
84: 
85: export fn process_backspace() ProcessKeyEventResult {
86:     if (gap > 0) {
87:         gap -= 1;
88:     } else switch (state) {
89:         .literal => state = .one_e,
90:         .idle => {},
91:         else => reset_state(),
92:     }
93:     return passthrough;
94: }
95: 
96: export fn process_key_event(char_code: u16) ProcessKeyEventResult {
97:     if (is_e(char_code)) {
98:         if (gap == 0 and state != .literal) return handle_e(char_code);
99:     } else if (!is_alphanumeric(char_code)) {
100:         reset_state();
101:         return passthrough;
102:     } else if (state == .idle) {
103:         return passthrough;
104:     }
105: 
106:     if (gap == 255) {
107:         reset_state();
108:         return passthrough;
109:     }
110:     gap += 1;
111:     return passthrough;
112: }

