3: private let syntheticTag: Int64 = 0x4C4558
4: 
5: class AppDelegate: NSObject, NSApplicationDelegate {
6:     var statusItem: NSStatusItem!
7:     var eventTap: CFMachPort?
8:     var syntheticSource: CGEventSource?
9: 
10:     func applicationDidFinishLaunching(_ notification: Notification) {
11:         syntheticSource = CGEventSource(stateID: .privateState)
12:         syntheticSource?.userData = syntheticTag
13:         setupMenuBar()
14:         requestAccessAndStartTap()
15:         observeAppSwitch()
16:     }
17: 
18:     private func setupMenuBar() {
19:         statusItem = NSStatusBar.system.statusItem(withLength: NSStatusItem.variableLength)
20:         if let button = statusItem.button {
21:             button.title = "Б▄╗"
22:         }
23:         let menu = NSMenu()
24:         menu.addItem(NSMenuItem(title: "Exit", action: #selector(NSApplication.terminate(_:)), keyEquivalent: "q"))
25:         statusItem.menu = menu
26:     }
27: 
28:     private func requestAccessAndStartTap() {
29:         let options = [kAXTrustedCheckOptionPrompt.takeUnretainedValue(): true] as CFDictionary
30:         if !AXIsProcessTrustedWithOptions(options) {
31:             print("Accessibility permission required. Please grant access in System Settings > Privacy & Security > Accessibility, then relaunch.")
32:             return
33:         }
34:         startEventTap()
35:     }
36: 
37:     private func observeAppSwitch() {
38:         NSWorkspace.shared.notificationCenter.addObserver(
39:             forName: NSWorkspace.didActivateApplicationNotification,
40:             object: nil,
41:             queue: .main
42:         ) { _ in
43:             reset_state()
44:         }
45:     }
46: 
47:     private func startEventTap() {
48:         let eventMask: CGEventMask = (1 << CGEventType.keyDown.rawValue)
49:             | (1 << CGEventType.flagsChanged.rawValue)
50:             | (1 << CGEventType.tapDisabledByTimeout.rawValue)
51:             | (1 << CGEventType.tapDisabledByUserInput.rawValue)
52: 
53:         let selfPtr = Unmanaged.passUnretained(self).toOpaque()
54: 
55:         guard let tap = CGEvent.tapCreate(
56:             tap: .cgSessionEventTap,
57:             place: .headInsertEventTap,
58:             options: .defaultTap,
59:             eventsOfInterest: eventMask,
60:             callback: eventTapCallback,
61:             userInfo: selfPtr
62:         ) else {
63:             print("Failed to create event tap. Ensure Input Monitoring permission is granted.")
64:             return
65:         }
66: 
67:         eventTap = tap
68:         let runLoopSource = CFMachPortCreateRunLoopSource(kCFAllocatorDefault, tap, 0)
69:         CFRunLoopAddSource(CFRunLoopGetCurrent(), runLoopSource, .commonModes)
70:         CGEvent.tapEnable(tap: tap, enable: true)
71:         print("Event tap started.")
72:     }
73: 
74:     func emitSyntheticEvents(result: ProcessKeyEventResult) {
75:         guard let source = syntheticSource else { return }
76: 
77:         for _ in 0..<result.num_backspaces {
78:             if let down = CGEvent(keyboardEventSource: source, virtualKey: 0x33, keyDown: true),
79:                let up = CGEvent(keyboardEventSource: source, virtualKey: 0x33, keyDown: false) {
80:                 down.post(tap: .cgSessionEventTap)
81:                 up.post(tap: .cgSessionEventTap)
82:             }
83:         }
84: 
85:         for i in 0..<Int(result.num_chars) {
86:             var char = result.chars[i]
87:             if let down = CGEvent(keyboardEventSource: source, virtualKey: 0, keyDown: true),
88:                let up = CGEvent(keyboardEventSource: source, virtualKey: 0, keyDown: false) {
89:                 down.keyboardSetUnicodeString(stringLength: 1, unicodeString: &char)
90:                 up.keyboardSetUnicodeString(stringLength: 1, unicodeString: &char)
91:                 down.post(tap: .cgSessionEventTap)
92:                 up.post(tap: .cgSessionEventTap)
93:             }
94:         }
95:     }
96: }
