98: func eventTapCallback(
99:     proxy: CGEventTapProxy,
100:     type eventType: CGEventType,
101:     event: CGEvent,
102:     userInfo: UnsafeMutableRawPointer?
103: ) -> Unmanaged<CGEvent>? {
104:     guard let userInfo = userInfo else {
105:         return Unmanaged.passUnretained(event)
106:     }
107:     let appDelegate = Unmanaged<AppDelegate>.fromOpaque(userInfo).takeUnretainedValue()
108: 
109:     if eventType == .tapDisabledByTimeout || eventType == .tapDisabledByUserInput {
110:         if let tap = appDelegate.eventTap {
111:             CGEvent.tapEnable(tap: tap, enable: true)
112:         }
113:         reset_state()
114:         return Unmanaged.passUnretained(event)
115:     }
116: 
117:     if eventType == .flagsChanged {
118:         return Unmanaged.passUnretained(event)
119:     }
120: 
121:     guard eventType == .keyDown else {
122:         return Unmanaged.passUnretained(event)
123:     }
124: 
125:     if event.getIntegerValueField(.eventSourceUserData) == syntheticTag {
126:         return Unmanaged.passUnretained(event)
127:     }
128: 
129:     let flags = event.flags
130:     let modifierMask: CGEventFlags = [.maskCommand, .maskControl, .maskAlternate]
131:     if !flags.intersection(modifierMask).isEmpty {
132:         reset_state()
133:         return Unmanaged.passUnretained(event)
134:     }
135: 
136:     let keyCode = event.getIntegerValueField(.keyboardEventKeycode)
137:     if keyCode == 0x33 {
138:         let _ = process_backspace()
139:         return Unmanaged.passUnretained(event)
140:     }
141: 
142:     var charCount: Int = 0
143:     event.keyboardGetUnicodeString(maxStringLength: 0, actualStringLength: &charCount, unicodeString: nil)
144: 
145:     guard charCount == 1 else {
146:         reset_state()
147:         return Unmanaged.passUnretained(event)
148:     }
149: 
150:     var unicodeChar: UniChar = 0
151:     event.keyboardGetUnicodeString(maxStringLength: 1, actualStringLength: &charCount, unicodeString: &unicodeChar)
152: 
153:     let result = process_key_event(unicodeChar)
154: 
155:     if result.swallow_event {
156:         appDelegate.emitSyntheticEvents(result: result)
157:         return nil
158:     }
159: 
160:     return Unmanaged.passUnretained(event)
161: }
